/** @format */

import request from "@/utils/request";

// 获取举报列表
export function getReportList(params) {
	return request({
		url: "/admin-api/community/reports/",
		method: "get",
		params,
	});
}

// 获取举报详情
export function getReportDetail(id) {
	return request({
		url: `/admin-api/community/reports/${id}/`,
		method: "get",
	});
}

// 开始审核举报
