	return request({
		url: `/admin-api/community/reports/${id}/start_review/`,
		method: "post",
	});
}

// 处理举报
export function resolveReport(id, data) {
	return request({
		url: `/admin-api/community/reports/${id}/resolve_report/`,
		method: "post",
		data,
	});
}

// 驳回举报
export function dismissReport(id, data) {
	return request({
		url: `/admin-api/community/reports/${id}/dismiss_report/`,
		method: "post",
